fn dfs(u: usize, adj: &Vec<Vec<usize>>, visited: &mut Vec<bool>) {
    visited[u] = true;
    for &v in &adj[u] {
        if !visited[v] {
            dfs(v, adj, visited);
        }
    }
}

use std::collections::VecDeque;

fn bfs(start: usize, adj: &Vec<Vec<usize>>) {
    let n = adj.len();
    let mut visited = vec![false; n];
    let mut q = VecDeque::new();
    visited[start] = true;
    q.push_back(start);
    while let Some(u) = q.pop_front() {
        for &v in &adj[u] {
            if !visited[v] {
                visited[v] = true;
                q.push_back(v);
            }
        }
    }
}

